external_knowledge:
- 'Compliant' refers to vehicles that meet the current compliance standards; 
- 'Distributor B' is a specific manufacturer; 
- A gross weight rating over 5000 kg indicates a heavy-duty vehicle; 
- 'Europe' is a region with specific distribution and compliance regulations.

sql:
SELECT COUNT(vehicle_id) AS compliant_vehicle_count
FROM vehicle_compliance
WHERE standard_id = 1 AND compliance_status = 'Compliant';

SELECT manufacturer_name
FROM vehicle_manufacturers
WHERE active = 1;

SELECT SUM(quantity) AS total_distributed
FROM vehicle_distribution
WHERE region = 'North America';

